scwin.f_Retrieve = async function () {
  var rail_yn = '';
  var v_odrWrkStpSeq = 0;
  var v_odrWrkStpSeqMax = 0;
  if ($c.gus.cfValidate($p, ed_odrNo)) {
    scwin.bSearch = true;
    var odrNo = ed_odrNo.getValue().replace(/\s*$/, '');
    scwin.v_dptWrkPlCd = '';
    scwin.v_bizDomCd = '';
    $c.gus.cfDisableKeyData($p);
    $c.gus.cfDisableAllBtn($p);
    $c.gus.cfEnableBtnOnly($p, [btn_close]);
    $c.gus.cfEnableBtnOnly($p, [btn_save]);
    ds_order.removeAll();
    ds_odrCntrSummary.removeAll();
    //ds_ctrtWrkPath.removeAll();
    ds_odrWrkPathStep.removeAll();
    ds_odrCntrWrkPath.removeAll();
    ds_ctrtWrkPathStep.removeAll();
    ds_odrWrkPathStepDetail.removeAll();

    // 그리드 총건수 초기화
    txt_totalRows.setValue(0);
    txt_totalRows2.setValue(0);

    // 작업장구분 Lokkup DataSet Setting
    ds_wrkPlClsCd.removeAll();

    //작업단계 LookUp DataSet Setting
    //ds_LkStepNo.removeAll();

    ds_orderSearch.set('odrNo', odrNo);
    scwin.gv_modifyYn = false;
    await $c.sbm.execute($p, sbm_retrieve);
    scwin.sbm_retrieve_submitdone();
    scwin.bSearch = false;
  }
};

