//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삽입 : 첫번째열을 선택한 경우 해당열 아래에 행삽입 후 이전 작업단계 정보 복사
//-------------------------------------------------------------------------
scwin.f_InsertRow = async function () {
  //현행포함 이후의 행들에 작업지시나 실적이 있을시 행을 삽입할 수 없다.
  for (var i = ds_odrWrkPathStepDetail.getRowPosition(); i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
    if (Number(ds_odrWrkPathStepDetail.getCellData(i, 'transRsltsSeq')) > 0) {
      $c.win.alert($p, '삽입하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삽입할 수 없습니다.');
      return;
    } else if (ds_odrWrkPathStepDetail.getCellData(i, 'transWrkIndictNo') != '') {
      $c.win.alert($p, '삽입하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삽입할 수 없습니다.');
      return;
    }
  }
  if (Number(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), 'odrWrkStpSeq')) % 10 < 9) {
    // 선택된 행 아래에 새로운 행 삽입
    var idx = ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowPosition() + 1);
    ds_odrWrkPathStepDetail.setRowPosition(idx);
    scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetail.getRowPosition() - 1, idx);
    scwin.f_setWorkStepInfoRefresh2(idx);
  } else {
    await $c.win.alert($p, '더이상 작업단계를 추가할수 없습니다.'); //작업단계을(를) 확인하여 주십시오
    return;
  }
  var ordNo = ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), 'odrNo');
  if (ordNo.substring(0, 3) == 'BC4' && scwin.rail_yn == 'Y' && scwin.memJson.userId != '991166' && scwin.memJson.userId != '030706') {
    if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), 'odrWrkStpSeq') >= scwin.v_odrWrkStpSeq) {
      $c.win.alert($p, '철송이후 단계를 수정하실수 없습니다.');
      await scwin.f_Retrieve();
    }
  }
  scwin.f_totalCnt();
};

//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = async function () {
  //현행포함 이후의 행들에 작업지시나 실적이 있을시 행을 삭제할 수 없다.
  for (var i = ds_odrWrkPathStepDetail.getRowPosition(); i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
    if (Number(ds_odrWrkPathStepDetail.getCellData(i, 'transRsltsSeq')) > 0) {
      await $c.win.alert($p, '삭제하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.');
      return;
    }
    if (i - 1 > -1) {
      if (Number(ds_odrWrkPathStepDetail.getCellData(i - 1, 'transRsltsSeq')) > 0) {
        await $c.win.alert($p, '삭제하고자 하는 단계가 포함된 운송작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.');
        return;
      }
    }
    if (ds_odrWrkPathStepDetail.getCellData(i, 'transWrkIndictNo') != '') {
      await $c.win.alert($p, '삭제하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.');
      return;
    }
    if (i - 1 > -1) {
      if (ds_odrWrkPathStepDetail.getCellData(i - 1, 'transWrkIndictNo') != '') {
        await $c.win.alert($p, '삭제하고자 하는 단계가 포함된 운송작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.');
        return;
      }
    }
  } //end of for(i)

  ds_odrWrkPathStepDetail.deleteRow(ds_odrWrkPathStepDetail.getRowPosition());
  scwin.f_setWorkStepInfoRefresh2(ds_odrWrkPathStepDetail.getRowPosition());
  scwin.f_totalCnt();
};
scwin.f_Undo = function () {
  var row = ds_odrWrkPathStepDetail.getRowPosition();
  if (ds_odrWrkPathStepDetail.getRowStatus(row) == 'C') {
    ds_odrWrkPathStepDetail.removeRow(row);
  } else {
    ds_odrWrkPathStepDetail.undoRow();
  }
  scwin.f_totalCnt();
};

//-------------------------------------------------------------------------
// 선택된 DATASET에 ROW 복사 ( 대상 DataSet, 원본 Row, 대상 Row )
//-------------------------------------------------------------------------
scwin.f_CopyDataRow = function (dataObject, sourceRow, targetRow) {
  var v_odrWrkStpSeq = Number(dataObject.getCellData(sourceRow, "odrWrkStpSeq"));
  var v_tempSeq = parseInt(v_odrWrkStpSeq / 10) * 10;
  var colId = "";
  for (var i = 0; i < dataObject.getColumnCount(); i++) {
    colId = dataObject.getColumnID(i);
    if (colId == "odrWrkStpSeq") {
      dataObject.setCellData(targetRow, colId, Number(dataObject.getCellData(sourceRow, colId)) + 1);
    } else if (colId == "arvWrkPlClsCd" || colId == "dptWrkPlClsCd" || colId == "dptWrkPlClsCdChange" || colId == "arvWrkPlClsCdChange") {
      dataObject.setCellData(targetRow, colId, " ");
    } else if (colId == "wrkPlClsCd" || colId == "wrkStpCd" || colId == "dptWrkPlCd" || colId == "dptWrkPlNm" || colId == "arvWrkPlCd" || colId == "arvWrkPlNm" || colId == "wrkLobranCd" || colId == "wrkLobranNm" || colId == "internalSellLodeptCd" || colId == "internalSellLodeptNm" || colId == "bizDomCd" || colId == "completeYn") {} else if (colId == "selpchItemCd") {
      dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
    } else if (colId == "selpchItemNm") {
      dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
    } else if (colId == "LINK_VAL") {
      dataObject.setCellData(targetRow, colId, "02");
    } else {
      dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
    }
  }

  // 오더작업단계순번 재정의
  for (var j = 1; j <= dataObject.CountRow; j++) {
    v_compSeq = eval(dataObject.getCellData(j, "odrWrkStpSeq") - v_tempSeq);
    if (dataObject.getCellData(j, "odrWrkStpSeq") > v_tempSeq && v_compSeq > 0 && v_compSeq < 10) {
      dataObject.setCellData(j, "odrWrkStpSeq", Number(dataObject.getCellData(j - 1, "odrWrkStpSeq")) + 1);
    }
  }
};

