//-------------------------------------------------------------------------
// 컨테이너 매입금액 조회(요율조회)
//-------------------------------------------------------------------------
scwin.f_retrievePchsAmt = async function (row) {
  ds_searchPchsAmt.set('branCd', ds_odrWrkPathStepDetail.getCellData(row, 'wrkLobranCd')); //작업물류점소코드
  ds_searchPchsAmt.set('clntNo', ds_odrWrkPathStepDetail.getCellData(row, 'ctrtClntNo')); //계약거래처코드
  ds_searchPchsAmt.set('copCoClntNo', ds_odrWrkPathStepDetail.getCellData(row, 'copCoClntNo')); //협력업체거래처코드
  ds_searchPchsAmt.set('odrKndCd', ds_odrWrkPathStepDetail.getCellData(row, 'odrKndCd')); //오더종류
  ds_searchPchsAmt.set('adptDt', ds_odrWrkPathStepDetail.getCellData(row, 'wrkStDt')); //적용일자(출발일자)
  ds_searchPchsAmt.set('dptWrkPlCd', ds_odrWrkPathStepDetail.getCellData(row, 'dptWrkPlCd')); //출발작업장코드
  ds_searchPchsAmt.set('arvWrkPlCd', ds_odrWrkPathStepDetail.getCellData(row, 'arvWrkPlCd')); //도착작업장코드
  ds_searchPchsAmt.set('cntrSizCd', ds_odrWrkPathStepDetail.getCellData(row, 'cntrSizCd')); //컨테이너SIZE코드
  ds_searchPchsAmt.set('fullEmptyClsCd', ds_odrWrkPathStepDetail.getCellData(row, 'fullEmptyClsCd')); //FULLEMPTY구분코드
  ds_searchPchsAmt.set('wrkStpCd', ds_odrWrkPathStepDetail.getCellData(row, 'wrkStpCd')); //작업단계코드

  if (ds_odrWrkPathStepDetail.getCellData(row, 'cntrSizCd') == '20') {
    ds_searchPchsAmt.set('cntrTrfCd', 'H'); //컨테이너요율코드  H:heavy, L:light, C:combine
  } else {
    ds_searchPchsAmt.set('cntrTrfCd', ' '); //컨테이너요율코드  H:heavy, L:light, C:combine
  }
  await $c.sbm.execute($p, sbm_retrievePchsAmt);

  //현재 데이터 셋의 로우 번호
  var rowNumber = ds_odrWrkPathStepDetail.getRowPosition();
  if (ds_resultPchsAmt.getRowCount() > 0) {
    //수정 부분이 마지막 단계가 아닐경우 (다음단계가 운송이며 작업지시가 있고 매입금액이 틀릴경우)
    if (rowNumber > -1 && rowNumber != ds_odrWrkPathStepDetail.getRowCount() - 1) {
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(rowNumber + 1, 'wrkPlClsCd').trim())) {
        if (!$c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(rowNumber + 1, 'transWrkIndictNo')) && ds_resultPchsAmt.getCellData(1, 'pchsAmt') != ds_odrWrkPathStepDetail.getCellData(rowNumber + 1, 'pchsAmt')) {
          if (!(await $c.win.confirm($p, '매입금액이 다릅니다. 계속하시겠습니까?'))) {
            ds_odrWrkPathStepDetail.undoRow(rowNumber); //취소시 이전으로 되돌린다.
            return;
          }
        }
      }
    }

    //수정 부분이 처음 단계가 아닐경우 (이전단계가 운송이며 작업지시가 있고 매입금액이 틀릴경우)
    if (rowNumber != 0) {
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(rowNumber - 1, 'wrkPlClsCd'))) {
        if (!$c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(rowNumber - 1, 'transWrkIndictNo')) && ds_resultPchsAmt.getCellData(1, 'pchsAmt') != ds_odrWrkPathStepDetail.getCellData(rowNumber - 1, 'pchsAmt')) {
          if (!(await $c.win.confirm($p, '매입금액이 다릅니다. 계속하시겠습니까?'))) {
            ds_odrWrkPathStepDetail.undoRow(rowNumber); //취소시 이전으로 되돌린다.
            return;
          }
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  //변경한 데이터가 있는지 체크한다. 
  if (ds_odrWrkPathStepDetail.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ['작업단계']); //변경된 정보가 없습니다.
    return;
  }

  // 품명별 작업경로를 선택하지 않은 경우 : 첫번째 품명의 작업경로는 반드시 선택되어야 한다.
  if (Number(ds_odrCntrWrkPath.getCellData(0, 'ctrtWrkPathSeq')) <= 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['작업경로']); //작업경로을(를) 선택하십시오.
    gr_odrCntrWrkPath.setFocusedCell(0, 'ctrtWrkPathSeq');
    return;
  }

  //PDA 작업 지시 여부값, EQ_CD 넣음
  var v_wrkIndictYn = '';
  var v_eqCd = '';
  for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
    if (ds_odrWrkPathStep.getCellData(j, 'wrkIndictYn') != '') {
      v_wrkIndictYn = 'Y';
      v_eqCd = ds_odrWrkPathStep.getCellData(j, 'eqCd');
      break;
    }
  }

  // 작업단계 정보 설정확인
  for (var i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
    //배차/미배차구분코드->작업장 변경 시 SMS는 배차 시에만 보내기때문
    ds_odrWrkPathStepDetail.setCellData(i, 'qryClsCd', hid_qryClsCd.getValue());

    //작업장 변경 시 변경 작업장 명은 dptWrkPlNm에, 이전작업장명을 dptWrkPlNm2에 넣어줌
    ds_odrWrkPathStepDetail.setCellData(i, 'dptWrkPlNm2', ds_odrWrkPathStepDetail.getOriginalCellData(i, 'dptWrkPlNm'));

    //PDA 작업 지시 여부값, EQ_CD 넣음
    ds_odrWrkPathStepDetail.setCellData(i, 'wrkIndictYn', v_wrkIndictYn);
    ds_odrWrkPathStepDetail.setCellData(i, 'eqCd', v_eqCd);

    // 작업구분이 지정되지 않은 경우(운송) 이전 단계의 작업장을 출발작업장으로, 다음 단계의 작업장을 도착작업장으로 설정한다.
    // 작업점소가 설정되지 않은 경우 작업점소는 이전 작업단계의 작업 점소를 설정한다.
    if (ds_odrWrkPathStepDetail.getCellData(i, 'wrkPlClsCd').trim() == '' && i > 0) {
      // 작업 점소
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'wrkLobranCd')) && ds_odrWrkPathStepDetail.getCellData(i, 'selpchItemCd') != '0000') {
        ds_odrWrkPathStepDetail.setCellData(i, 'wrkLobranCd', ds_odrWrkPathStepDetail.getCellData(i - 1, 'wrkLobranCd'));
      }
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'wrkLobranNm')) && ds_odrWrkPathStepDetail.getCellData(i, 'selpchItemCd') != '0000') {
        ds_odrWrkPathStepDetail.setCellData(i, 'wrkLobranNm', ds_odrWrkPathStepDetail.getCellData(i - 1, 'wrkLobranNm'));
      }

      // 작업장
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'dptWrkPlCd'))) {
        ds_odrWrkPathStepDetail.setCellData(i, 'dptWrkPlCd', ds_odrWrkPathStepDetail.getCellData(i - 1, 'dptWrkPlCd'));
      }
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'arvWrkPlCd'))) {
        ds_odrWrkPathStepDetail.setCellData(i, 'arvWrkPlCd', ds_odrWrkPathStepDetail.getCellData(i + 1, 'dptWrkPlCd'));
      }
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'arvWrkPlNm'))) {
        ds_odrWrkPathStepDetail.setCellData(i, 'arvWrkPlNm', ds_odrWrkPathStepDetail.getCellData(i + 1, 'dptWrkPlNm'));
      }

      // 매출귀속부서    
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'internalSellLodeptCd')) && ds_odrWrkPathStepDetail.getCellData(i, 'selpchItemCd') != '0000') {
        ds_odrWrkPathStepDetail.setCellData(i, 'internalSellLodeptCd', ds_odrWrkPathStepDetail.getCellData(i - 1, 'internalSellLodeptCd'));
      }
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i, 'internalSellLodeptNm')) && ds_odrWrkPathStepDetail.getCellData(i, 'selpchItemCd') != '0000' && !$c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(i - 1, 'internalSellLodeptNm'))) {
        ds_odrWrkPathStepDetail.setCellData(i, 'internalSellLodeptNm', ds_odrWrkPathStepDetail.getCellData(i - 1, 'internalSellLodeptNm'));
      }
    }
  }

  // 현재 품명의 작업단계 정보의  Vaildation 을 검사한다.
  if (!(await $c.gus.cfValidate($p, [gr_odrWrkPathStpDetail], [], true))) return;

  // 필수 입력 확인
  for (var idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
    //해당 로우가 변경여부가 없을경우 패스한다.
    if (ds_odrWrkPathStepDetail.getRowStatus(idx) == 'R') {
      continue;
    }

    // 작업장 확인 - 작업구분이 운송이 아닌 경우 작업장은 필수 입력 항목입니다.
    if (!$c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'wrkPlClsCd')) && $c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'dptWrkPlNm'))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['작업장']);
      gr_odrWrkPathStpDetail.setFocusedCell(idx, 'dptWrkPlNm');
      return false;
    }

    // 매출입항목이 무매출이 아니경우에는 작업점소, 매출귀속부서는 필수 입력항목입니다.
    if (ds_odrWrkPathStepDetail.getCellData(idx, 'selpchItemCd') != '0000') {
      // 작업점소 확인
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'wrkLobranCd'))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['작업점소']);
        gr_odrWrkPathStpDetail.setFocusedCell(idx, 'wrkLobranNm');
        return false;
      }

      //매출귀속부서 확인
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'internalSellLodeptCd'))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['매출귀속부서']);
        gr_odrWrkPathStpDetail.setFocusedCell(idx, 'internalSellLodeptNm');
        return false;
      }
    } else if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'wrkPlClsCd'))) {
      // 작업점소 확인
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'wrkLobranCd'))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['작업점소']);
        gr_odrWrkPathStpDetail.setFocusedCell(idx, 'wrkLobranNm');
        return false;
      }

      //매출귀속부서 확인
      if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'internalSellLodeptCd'))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['매출귀속부서']);
        gr_odrWrkPathStpDetail.setFocusedCell(idx, 'internalSellLodeptNm');
        return false;
      }
    }
    if (ds_odrWrkPathStepDetail.getCellData(idx, 'wrkStDt').length < 8) {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['시작일자']);
      gr_odrWrkPathStpDetail.setFocusedCell(idx, 'wrkStDt');
      return false;
    }
    if (ds_odrWrkPathStepDetail.getCellData(idx, 'wrkStHh').length < 4) {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['시작시간']);
      gr_odrWrkPathStpDetail.setFocusedCell(idx, 'wrkStHh');
      return false;
    }
    if (ds_odrWrkPathStepDetail.getCellData(idx, 'wrkEndDt').length < 8) {
      $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['종료일자']);
      gr_odrWrkPathStpDetail.setFocusedCell(idx, 'wrkEndDt');
      return false;
    }
    if (ds_odrWrkPathStepDetail.getCellData(idx, 'wrkEndHh').length < 4) {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['종료시간']);
      gr_odrWrkPathStpDetail.setFocusedCell(idx, 'wrkEndHh');
      return false;
    }
    if ($c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(idx, 'fullEmptyClsCd'))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ['F/E']);
      gr_odrWrkPathStpDetail.setFocusedCell(idx, 'fullEmptyClsCd');
      return false;
    }
  }
  ds_odrCntrWrkPath.setRowPosition(0);

  // 첫번째 품명의 작업단계 정보의  Vaildation 을 검사한다.
  if (!(await $c.gus.cfValidate($p, [gr_odrWrkPathStpDetail], [], true))) return;
  hid_chkUseFilter.setValue(false);
  var v_wrkPathRows = ds_odrCntrWrkPath.getRowCount();
  var v_wrkPathStepRows = ds_odrWrkPathStepDetail.getRowCount();

  // 첫번째 작업단계의 정보를 저장한다.
  var v_odrNo = ds_odrCntrWrkPath.getCellData(0, 'odrNo');
  var v_commSeq = ds_odrCntrWrkPath.getCellData(0, 'cntrSeq');

  // 첫번째 작업 경로 중 사용하지 않는 작업단계를 삭제한다.
  var i = 0;
  var chk = 1;

  //매출순번 기억(매출순번은 첫로우의 순번을 기억한다. 작업지시가 있으며 작업단계가 추가나 삭제 되었을시 통합매출에 적용하기 위하여)
  var v_sellSeq = ds_odrWrkPathStepDetail.getCellData(0, 'sellSeq');
  var v_transWrkIndictYn = 0;

  //작업지시여부와 매출 순번을 기억(현 컨테이너가 작업지시가 있는지를 기억)
  for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
    if (ds_odrWrkPathStepDetail.getCellData(j, 'transWrkIndictNo') != '') {
      v_transWrkIndictYn = 1;
      break;
    }
  }

  //변경되는 로우에 작업지시여부와 매출순번, 운송단계의 매출입항목이 무매출일경우을 운송료로 셋팅
  var v_dptWrkPlCd1 = '';
  var v_arvWrkPlCd1 = '';
  var v_dptWrkPlCd2 = '';
  var v_arvWrkPlCd2 = '';
  for (var j = 0; j < ds_odrWrkPathStep.getRowCount(); j++) {
    if (ds_odrWrkPathStep.getCellData(j, 'wrkPlClsCd') == 'D' && ds_odrWrkPathStep.getCellData(j, 'wrkStpCd') == '0024') {
      v_dptWrkPlCd1 = ds_odrWrkPathStep.getCellData(j, 'dptWrkPlCd');
      v_arvWrkPlCd1 = ds_odrWrkPathStep.getCellData(j, 'arvWrkPlCd');
    }
    if (ds_odrWrkPathStep.getCellData(j, 'wrkPlClsCd') == 'D' && ds_odrWrkPathStep.getCellData(j, 'wrkStpCd') == '0025') {
      v_dptWrkPlCd2 = ds_odrWrkPathStep.getCellData(j, 'dptWrkPlCd');
      v_arvWrkPlCd2 = ds_odrWrkPathStep.getCellData(j, 'arvWrkPlCd');
    }
  }
  for (var j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
    if (ds_odrWrkPathStepDetail.getRowStatus(j) != 'R') {
      ds_odrWrkPathStepDetail.setCellData(j, 'transWrkIndictYn', v_transWrkIndictYn);
      ds_odrWrkPathStepDetail.setCellData(j, 'sellSeq', v_sellSeq);
    }
    if (ds_odrWrkPathStepDetail.getCellData(j, 'wrkPlClsCd') == 'D' && ds_odrWrkPathStepDetail.getCellData(j, 'wrkStpCd') == '0024') {
      if (ds_odrWrkPathStepDetail.getCellData(j, 'dptWrkPlCd') != v_dptWrkPlCd1 || ds_odrWrkPathStepDetail.getCellData(j, 'arvWrkPlCd') != v_arvWrkPlCd1) {
        await $c.win.alert($p, 'Door 작업장은 수정할수 없습니다.!!!');
        chk = 2;
      }
    }
    if (ds_odrWrkPathStepDetail.getCellData(j, 'wrkPlClsCd') == 'D' && ds_odrWrkPathStepDetail.getCellData(j, 'wrkStpCd') == '0025') {
      if (ds_odrWrkPathStepDetail.getCellData(j, 'dptWrkPlCd') != v_dptWrkPlCd2 || ds_odrWrkPathStepDetail.getCellData(j, 'arvWrkPlCd') != v_arvWrkPlCd2) {
        await $c.win.alert($p, 'Door 작업장은 수정할수 없습니다.!!!');
        chk = 2;
      }
    }
  }

  // AS-IS의 경우 DataList 연결을 끝어버려 f_validChk 가 무조건 true로 됨. (scwin.f_validChk() 무의미)

  hid_chkUseFilter.setValue(true);

  // 필수 입력사항을 체크    
  if (chk == 1) {
    // 선택되지 않은 작업단계정보 삭제
    if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
      // 작업경로 , 작업단계 정보 저장
      for (var i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        if (ds_odrWrkPathStepDetail.setCellData(i, 'sellAdptYn') == '') {
          ds_odrWrkPathStepDetail.setCellData(i, 'sellAdptYn', '0');
        }
      }
      $c.sbm.execute($p, sbm_save);
    }
  }
};

