//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------

scwin.f_chkOpenCommPopUpGrid = async function (type, disGubun, ds, row, pCodeCol, pNameCol, pClose, pAllSearch, options) {
  var codeVal = pCodeCol ? ds.getCellData(row, pCodeCol) : '';
  var nameVal = pNameCol ? ds.getCellData(row, pNameCol) : '';
  if (pCodeCol) ds.setCellData(row, pCodeCol, '');
  if (pNameCol) ds.setCellData(row, pNameCol, '');
  if (type == 'CODE') {
    if (codeVal == '') return;
  } else if (type == 'NAME') {
    if (nameVal == '') return;
  }
  if (type == 'CODE') {
    return await scwin.f_openCommPopUpGridSync(disGubun, row, codeVal, '', pClose, pAllSearch, options);
  } else if (type == 'NAME') {
    return await scwin.f_openCommPopUpGridSync(disGubun, row, '', nameVal, pClose, pAllSearch, options);
  } else if (type == 'SEARCH') {
    return await scwin.f_openCommPopUpGridSync(disGubun, row, codeVal, nameVal, pClose, pAllSearch, options);
  }
};
scwin.f_openCommPopUpGridSync = function (disGubun, row, pCode, pName, pClose, pAllSearch, options) {
  return new Promise(function (resolve, reject) {
    var _options = $.extend({
      callback: resolve
    }, options);
    scwin.f_openCommPopUpGrid(disGubun, row, pCode, pName, pClose, pAllSearch, _options);
  });
};
