scwin.f_ds_LkStepNoFilter = function (row) {
  var v_wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim();
  var v_fltrCd1 = "";

  // 작업장구분 코드로 FLTR_CD_1 값 조회 
  for (i = 0; i < dlt_commonCodeLO121.getRowCount(); i++) {
    if (v_wrkPlClsCd == dlt_commonCodeLO121.getCellData(i, "cd")) {
      v_fltrCd1 = dlt_commonCodeLO121.getCellData(i, "fltrCd1");
      break;
    }
  }
  if (v_fltrCd1 == "02") {
    // 하역 (작업단계코드 : 01)
    ds_odrWrkPathStepDetail.setCellData(row, 'LINK_VAL', '01');
  } else if (v_fltrCd1 != "02" && v_fltrCd1 != "") {
    // 본관,포장 (작업단계코드 : 03,04)
    ds_odrWrkPathStepDetail.setCellData(row, 'LINK_VAL', '03');
  } else {
    // 운송 (작업단계코드 : 02)
    ds_odrWrkPathStepDetail.setCellData(row, 'LINK_VAL', '02');
  }
};
