//-------------------------------------------------------------------------
// 대문자 전환 이벤트 함수
//-------------------------------------------------------------------------
scwin.upperCase = function (e) {
  var obj = window[e.target.id];
  if (obj.setValue) {
    var oldVal = obj._oldValue;
    obj.setValue(obj.getValue().toUpperCase());
    obj._oldValue = oldVal;
  }
};

//-------------------------------------------------------------------------
// 그리드 포맷팅함수
//-------------------------------------------------------------------------
scwin.setCustomFormatter = function (orgVal, formatVal, rowIndex, colIndex) {
  var grid = this.org_id;
  var colId = this.getColumnID(colIndex);
  var retVal = formatVal;
  switch (grid) {
    case "gr_odrCntrWrkPath":
      break;
    case "gr_odrWrkPathStpDetail":
      if (colId == "AA") {
        var chkVal = ds_odrWrkPathStepDetail.getCellData(rowIndex, "transRsltsSeq");
        return chkVal == 0 ? "" : "Y";
      } else if (colId == "BB") {
        var chkVal = ds_odrWrkPathStepDetail.getCellData(rowIndex, "transWrkIndictNo");
        return chkVal == null || chkVal == "" ? "" : "Y";
      }
      break;
    default:
      break;
  }
  return retVal;
};

