scwin.ds_order_ondataload = function () {
  // ds_order OnLoadCompleted 이벤트
  if (ds_order.getRowCount() == 0) {
    scwin.f_FieldClear();

    // 오더정보 초기화
    txt_realMchtclntNm.setValue('');
    txt_ctrtClntNm.setValue('');
    txt_ctrtNo.setValue('');
    txt_odrKndNm.setValue('');
  } else {
    ds_order.setRowPosition(0);
    // 오더 종류가 내수운송인 경우 수요가로 명칭 변환
    if (ds_order.getCellData(0, 'odrKndCd').substr(0, 1) == 'D') {
      txt_realMchtClntNm.setValue('수요가');
      // 수요가명 설정
      txt_realMchtclntNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'dmndNm'));
      // 수요가 코드 설정
      hid_realMchtclntNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'dmndNo'));
    } else {
      txt_realMchtClntNm.setValue('실화주');
      // 실화주명 설정
      txt_realMchtclntNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'realMchtClntNm'));
      // 실화주 코드 설정
      hid_realMchtclntNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'realMchtClntNo'));
    }
    scwin.f_setDisplayOdrKndCd(ds_order.getCellData(1, 'odrKndCd'));

    // 계약거래처명 설정
    txt_ctrtClntNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'ctrtClntNm'));
    // 계약번호 설정
    txt_ctrtNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'ctrtNo'));
    // 오더종류명 설정
    txt_odrKndNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'odrKndNm'));

    // 계약거래처 코드 설정
    hid_ctrtClntNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'ctrtClntNo'));
    // 계약번호 설정
    hid_ctrtNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'ctrtNo'));
    // 오더종류코드 설정
    hid_odrKndCd.setValue(ds_order.getCellData(ds_order.getRowPosition(), 'odrKndCd'));
    if (ds_order.getCellData(ds_order.getRowPosition(), 'odrDelYn') == DsConstants.YN_YES) {
      gr_odrCntrWrkPath.options.readOnly = true;
      scwin.f_setGridReadOnly(gr_odrWrkPathStpDetail, true);
      $c.gus.cfDisableBtnOnly($p, [btnInsertRow, btnDeleteRow, btnUndoMark]);
    } else {
      gr_odrCntrWrkPath.options.readOnly = false;
      scwin.f_setGridReadOnly(gr_odrWrkPathStpDetail, false);
      $c.gus.cfEnableBtnOnly($p, [btnUndoMark]);
    }
  }
};

