// 오더 작업경로별 작업단계 상세 조회 Event (ds_odrWrkPathStepDetail)
//-------------------------------------------------------------------------------------
scwin.ds_odrWrkPathStepDetail_ondataload = function () {
  scwin.f_totalCnt();
};
scwin.ds_odrWrkPathStepDetail_onrowpositionchange = function (info) {
  if (ds_odrWrkPathStepDetail.getRowCount() == 0) return;
  var row = info.newRowIndex;

  //현행포함 이후의 행들에 실적이 있을시 수정할 수 없다.
  var modifyYn = true;
  for (var i = row; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
    if (ds_odrWrkPathStepDetail.getCellData(i, 'transWrkIndictNo') != '') {
      modifyYn = false;
      break;
    }
  }
  if (modifyYn) {
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkPlClsCd', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkStpCd', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('dptWrkPlNm', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkLobranNm', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('internalSellLodeptNm', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkStDt', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkStHh', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkEndDt', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkEndHh', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('fullEmptyClsCd', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('selpchItemNm', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('smsYn', false);
  }

  //작업단계 수정모드 설정
  scwin.f_checkWorkStepEditMode(row);
  if (ds_odrWrkPathStep.getRowCount() == 0) {
    if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), 'wrkPlClsCd').trim() == '') {
      // 작업구분이 운송인 경우 작업장 입력불가
      gr_odrWrkPathStpDetail.setColumnReadOnly('dptWrkPlNm', true);
    } else {
      gr_odrWrkPathStpDetail.setColumnReadOnly('dptWrkPlNm', false);
    }
  }
  if (ds_odrWrkPathStepDetail.getCellData(row, 'selpchItemCd').trim() == SdConstants.SELPCH_ITEM_CD_NOSELL && !$c.gus.cfIsNull($p, ds_odrWrkPathStepDetail.getCellData(row, 'wrkPlClsCd').trim())) {
    // 매출입항목이 무매출이고, 운송단계가 아닌인 경우 작업점소, 매출귀속부서 입력 불가
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkLobranNm', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('internalSellLodeptNm', true);
  } else {
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkLobranNm', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('internalSellLodeptNm', false);
    gr_odrWrkPathStpDetail.setColumnReadOnly('smsYn', false);
  }
  if (!modifyYn) {
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkPlClsCd', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkStpCd', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('selpchItemNm', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('dptWrkPlNm', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkLobranNm', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('internalSellLodeptNm', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkStDt', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkStHh', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkEndDt', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('wrkEndHh', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('fullEmptyClsCd', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('selpchItemNm', true);
    gr_odrWrkPathStpDetail.setColumnReadOnly('smsYn', false);
  }
  if (gr_odrWrkPathStpDetail.getGridReadOnly()) {
    gr_odrWrkPathStpDetail.setColumnReadOnly('smsYn', true);
  }

  // 작업단계 수정 시 작업경로 체크 없으면 에러메세지
  // 작업단계 수정 시 작업경로 체크 제어
  if (row > -1) {
    var vCntRow = 0;
    var vChgCount = 0;
    var vChgRow = 0;
    var vCurRowStatus = 'R';
    for (var i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
      if (ds_odrCntrWrkPath.getCellData(i, 'chk') == 1) {
        vCntRow++;
      }
    }
    for (var i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
      vCurRowStatus = ds_odrWrkPathStepDetail.getRowStatus(i);
      if (vCurRowStatus == 'C' || vCurRowStatus == 'U') {
        vChgCount++;
        vChgRow = i;
      }
    }
    if (vChgCount > 0 && row != vChgRow) {
      if (vCntRow == 0) {
        $c.win.alert($p, '일괄수정할 컨테이너를 먼저 선택 한 후 작업단계 수정을 해주시기 바랍니다.');
        return false;
      }
    }
  }
};

